-- DELETE: partial removal, triggers fire, per-row log
DELETE FROM Orders WHERE OrderDate < '2020-01-01';

-- TRUNCATE: all rows gone, minimal log, identity resets, no WHERE
TRUNCATE TABLE StagingOrders;

-- DROP: table no longer exists
DROP TABLE StagingOrders;

-- Baseline I/O measurement
SET STATISTICS IO ON;
SET STATISTICS TIME ON;

-- Non-SARGable (BAD) -- function prevents index seek
SELECT * FROM Orders WHERE YEAR(OrderDate) = 2024;

-- SARGable (GOOD) -- allows index seek
SELECT OrderId, CustomerId, Total
FROM Orders
WHERE OrderDate >= '2024-01-01' AND OrderDate < '2025-01-01';

-- Covering index: seek on CustomerId, include Total to avoid Key Lookup
CREATE NONCLUSTERED INDEX IX_Orders_CustomerId_Inc
  ON Orders (CustomerId)
  INCLUDE (Total, OrderDate);

-- Local temp table
CREATE TABLE #RecentOrders (
    OrderId   INT,
    Total     DECIMAL(18,2)
);
INSERT INTO #RecentOrders
    SELECT OrderId, Total FROM Orders WHERE OrderDate > DATEADD(DAY,-30,GETDATE());
SELECT * FROM #RecentOrders;
DROP TABLE IF EXISTS #RecentOrders;

-- Table variable (no indexes except PK/UNIQUE at declaration)
DECLARE @TopCustomers TABLE (
    CustomerId INT PRIMARY KEY,
    TotalSpent DECIMAL(18,2)
);
INSERT INTO @TopCustomers
    SELECT TOP 10 CustomerId, SUM(Total) FROM Orders GROUP BY CustomerId ORDER BY SUM(Total) DESC;
SELECT * FROM @TopCustomers;

-- Stored procedure with error handling
CREATE OR ALTER PROCEDURE usp_GetCustomerOrders
    @CustomerId INT,
    @StartDate  DATE = NULL
AS
BEGIN
    SET NOCOUNT ON;
    SELECT o.OrderId, o.Total, o.OrderDate
    FROM Orders o
    WHERE o.CustomerId = @CustomerId
      AND (@StartDate IS NULL OR o.OrderDate >= @StartDate)
    ORDER BY o.OrderDate DESC;
END;

-- Execute
EXEC usp_GetCustomerOrders @CustomerId = 42, @StartDate = '2024-01-01';

-- Parameterized inline SQL (also safe, also cached)
EXEC sp_executesql
    N'SELECT * FROM Orders WHERE CustomerId = @cid',
    N'@cid INT',
    @cid = 42;

-- Atomic bank transfer: both debit and credit must succeed together
SET XACT_ABORT ON;
BEGIN TRY
    BEGIN TRANSACTION;

    UPDATE Accounts SET Balance = Balance - 500 WHERE AccountId = 1;
    UPDATE Accounts SET Balance = Balance + 500 WHERE AccountId = 2;

    -- Consistency check
    IF (SELECT Balance FROM Accounts WHERE AccountId = 1) < 0
        THROW 50001, 'Insufficient funds', 1;

    COMMIT TRANSACTION;
END TRY
BEGIN CATCH
    IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;
    THROW;  -- re-raise the error
END CATCH;

-- Set isolation level for the current session
SET TRANSACTION ISOLATION LEVEL READ COMMITTED;  -- default
SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED; -- dirty reads allowed
SET TRANSACTION ISOLATION LEVEL REPEATABLE READ;
SET TRANSACTION ISOLATION LEVEL SERIALIZABLE;
SET TRANSACTION ISOLATION LEVEL SNAPSHOT;

-- Enable RCSI at database level (eliminates read-write blocking)
ALTER DATABASE AdventureWorks
    SET READ_COMMITTED_SNAPSHOT ON WITH ROLLBACK IMMEDIATE;

-- Query hint equivalent of READ UNCOMMITTED (avoid in production)
SELECT * FROM Orders WITH (NOLOCK);

-- Normalized (3NF)
CREATE TABLE Departments (DepartmentId INT PRIMARY KEY, DepartmentName NVARCHAR(100));
CREATE TABLE Employees  (EmployeeId INT PRIMARY KEY, Name NVARCHAR(100), DepartmentId INT REFERENCES Departments(DepartmentId));

-- Denormalized (for a read-heavy reporting table)
CREATE TABLE EmployeeReportView (
    EmployeeId     INT,
    EmployeeName   NVARCHAR(100),
    DepartmentId   INT,
    DepartmentName NVARCHAR(100)  -- redundant but avoids join in reports
);

CREATE TABLE Departments (
    DepartmentId   INT         IDENTITY PRIMARY KEY,  -- clustered by default
    DepartmentCode CHAR(4)     NOT NULL UNIQUE,        -- unique, allows one NULL
    DepartmentName NVARCHAR(100) NOT NULL
);

CREATE TABLE Employees (
    EmployeeId   INT         IDENTITY PRIMARY KEY,
    Email        NVARCHAR(256) NOT NULL UNIQUE,         -- unique key
    DepartmentId INT         NOT NULL
        REFERENCES Departments(DepartmentId)            -- foreign key
        ON DELETE RESTRICT
        ON UPDATE CASCADE
);

-- Index the FK column to avoid table scans on parent DELETE
CREATE INDEX IX_Employees_DepartmentId ON Employees (DepartmentId);

-- Surrogate PK + separate unique constraint for natural key
CREATE TABLE Products (
    ProductId  INT         IDENTITY PRIMARY KEY,   -- surrogate
    SKU        NVARCHAR(50) NOT NULL UNIQUE,        -- natural key enforced separately
    Name       NVARCHAR(200) NOT NULL,
    CreatedAt  DATETIME2    NOT NULL DEFAULT SYSUTCDATETIME()
);

-- Partition function and scheme for date-based partitioning
CREATE PARTITION FUNCTION pf_OrderDate (DATE)
    AS RANGE RIGHT FOR VALUES ('2022-01-01','2023-01-01','2024-01-01','2025-01-01');

CREATE PARTITION SCHEME ps_OrderDate
    AS PARTITION pf_OrderDate ALL TO ([PRIMARY]);

CREATE TABLE OrdersPartitioned (
    OrderId   BIGINT IDENTITY,
    OrderDate DATE NOT NULL,
    Total     DECIMAL(18,2)
) ON ps_OrderDate(OrderDate);
